import React, { useEffect, useState } from "react";
import axios from "axios";

function MyPredictionHistory() {
  const [history, setHistory] = useState([]);

  const user = JSON.parse(localStorage.getItem("user"));

  useEffect(() => {
    if (user?.email) {
      axios
        .get(`http://localhost:5000/history/${user.email}`)
        .then((res) => {
          console.log("HISTORY DATA 👉", res.data);
          setHistory(res.data);
        })
        .catch((err) => console.log(err));
    }
  }, [user]);

  return (
    <div style={{ padding: "30px" }}>
      <h2>📊 My Prediction History</h2>

      <p><strong>Total Predictions:</strong> {history.length}</p>

      <table border="1" cellPadding="10" style={{ width: "100%", textAlign: "center" }}>
        <thead style={{ backgroundColor: "#f2f2f2" }}>
          <tr>
            <th>#</th>
            <th>Date & Time</th>
            <th>Role</th>
            <th>Experience</th>
            <th>Salary (INR)</th>
          </tr>
        </thead>

        <tbody>
          {history.length > 0 ? (
            history.map((item, index) => (
              <tr key={index}>
                {/* Serial Number */}
                <td>{index + 1}</td>

                {/* Date */}
                <td>
                  {item.createdAt
                    ? new Date(item.createdAt).toLocaleString()
                    : "N/A"}
                </td>

                {/* Role */}
                <td>{item.JobRole || "N/A"}</td>

                {/* Experience */}
                <td>{item.Experience ? `${item.Experience} yrs` : "0 yrs"}</td>

                {/* Salary */}
                <td>
                  ₹{" "}
                  {item.predictedSalary
                    ? Number(item.predictedSalary).toLocaleString("en-IN")
                    : "0"}
                </td>
              </tr>
            ))
          ) : (
            <tr>
              <td colSpan="5">No history found</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}

export default MyPredictionHistory;
